/**
 * Game Context — Central State Management
 * 
 * Provides the complete gamification state to all components.
 * Persists state to localStorage for session continuity.
 * Exposes action dispatchers for activity completion, mission claiming, etc.
 * 
 * This context is the single source of truth for all gamification data
 * and drives the entire reward/feedback loop of the application.
 */

import { createContext, useContext, useReducer, useEffect, useCallback } from 'react';
import { calculateActivityPoints, calculateStreakBonus } from '../engine/pointsEngine.js';
import { computeLevel, checkLevelUp } from '../engine/levelEngine.js';
import { evaluateNewBadges } from '../engine/badgeEngine.js';
import { computeStreak, getStreakMessage } from '../engine/streakEngine.js';
import { computeMissionProgress } from '../engine/missionEngine.js';
import { rankUsers, getUserRank } from '../engine/leaderboardEngine.js';
import seedUsers from '../data/users.js';
import activities from '../data/activities.js';

const STORAGE_KEY = 'gamification_state';

/* ─── Initial State ─── */

function getInitialState() {
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      return JSON.parse(saved);
    }
  } catch { /* ignore */ }

  return {
    // User identity
    userId: 'user_current',
    userName: 'Demo Student',
    userAvatar: '🧑‍🎓',

    // Points & Level
    totalPoints: 0,

    // Activity tracking
    activitiesCompleted: 0,
    quizzesCompleted: 0,
    quizzesAbove70: 0,
    perfectQuizzes: 0,
    sessionQuizzes: 0,
    completedActivityIds: [],
    activityLog: [],
    activityDates: [],

    // Badges
    badgesEarned: [],

    // Streaks
    currentStreak: 0,
    longestStreak: 0,

    // Missions
    completedMissionIds: [],
    missionsCompleted: 0,

    // Topic exploration
    topicsExplored: 0,
    exploredTopics: [],

    // Derived / meta
    hasPerfectQuiz: false,
    hasImprovedScore: false,
    leaderboardRank: 0,

    // Notifications queue
    notifications: [],

    // Session metadata
    joinDate: new Date().toISOString().split('T')[0],
    lastActiveDate: null,
  };
}

/* ─── Reducer ─── */

function gameReducer(state, action) {
  switch (action.type) {

    case 'COMPLETE_ACTIVITY': {
      const { activityId, correctAnswers, totalQuestions, topic, hintsUsed } = action.payload;

      // Calculate points
      const activity = activities.find((a) => a.id === activityId);
      if (!activity) return state;

      const pointsResult = calculateActivityPoints(activity.points, correctAnswers, totalQuestions, hintsUsed);
      const streakBonus = calculateStreakBonus(state.currentStreak);
      const totalEarned = pointsResult.earnedPoints + streakBonus;

      // Streak update
      const now = new Date().toISOString();
      const newActivityDates = [...state.activityDates, now];
      const streakInfo = computeStreak(newActivityDates);

      // Topic tracking
      const newExploredTopics = state.exploredTopics.includes(topic)
        ? state.exploredTopics
        : [...state.exploredTopics, topic];

      // Previous scores for this activity (for persistence badge)
      const previousAttempts = state.activityLog.filter((a) => a.activityId === activityId);
      const previousBest = previousAttempts.length > 0
        ? Math.max(...previousAttempts.map((a) => a.accuracy))
        : null;
      const hasImprovedScore = previousBest !== null && pointsResult.accuracy > previousBest;

      // Build new state
      const newState = {
        ...state,
        totalPoints: state.totalPoints + totalEarned,
        activitiesCompleted: state.activitiesCompleted + 1,
        quizzesCompleted: state.quizzesCompleted + 1,
        quizzesAbove70: state.quizzesAbove70 + (pointsResult.accuracy >= 70 ? 1 : 0),
        perfectQuizzes: state.perfectQuizzes + (pointsResult.isPerfect ? 1 : 0),
        sessionQuizzes: state.sessionQuizzes + 1,
        completedActivityIds: [...new Set([...state.completedActivityIds, activityId])],
        activityLog: [...state.activityLog, {
          activityId,
          topic,
          accuracy: pointsResult.accuracy,
          pointsEarned: totalEarned,
          completedAt: now,
          correctAnswers,
          totalQuestions,
        }],
        activityDates: newActivityDates,
        currentStreak: streakInfo.currentStreak,
        longestStreak: Math.max(state.longestStreak, streakInfo.currentStreak),
        hasPerfectQuiz: state.hasPerfectQuiz || pointsResult.isPerfect,
        hasImprovedScore: state.hasImprovedScore || hasImprovedScore,
        exploredTopics: newExploredTopics,
        topicsExplored: newExploredTopics.length,
        lastActiveDate: now,
      };

      // Check for new badges
      const newBadges = evaluateNewBadges(newState, state.badgesEarned);
      if (newBadges.length > 0) {
        newState.badgesEarned = [...state.badgesEarned, ...newBadges.map((b) => b.id)];
      }

      // Check for level up
      const levelUp = checkLevelUp(state.totalPoints, newState.totalPoints);

      // Build notifications
      const notifications = [];
      notifications.push({
        type: 'points',
        title: `+${totalEarned} Points!`,
        message: `${pointsResult.accuracy}% accuracy${streakBonus > 0 ? ` (+${streakBonus} streak bonus)` : ''}`,
        id: Date.now(),
      });
      if (levelUp) {
        notifications.push({
          type: 'levelup',
          title: 'Level Up!',
          message: `You reached Level ${levelUp.newLevel.level}: ${levelUp.newLevel.title} ${levelUp.newLevel.icon}`,
          id: Date.now() + 1,
        });
      }
      newBadges.forEach((badge, i) => {
        notifications.push({
          type: 'badge',
          title: 'Badge Unlocked!',
          message: `${badge.icon} ${badge.name}`,
          id: Date.now() + 2 + i,
        });
      });

      newState.notifications = [...state.notifications, ...notifications];

      // Update leaderboard rank
      const allUsers = seedUsers.map((u) =>
        u.id === 'user_current' ? { ...u, totalPoints: newState.totalPoints, badgesEarned: newState.badgesEarned, currentStreak: newState.currentStreak } : u
      );
      const ranked = rankUsers(allUsers, 'points');
      newState.leaderboardRank = getUserRank(ranked, 'user_current');

      return newState;
    }

    case 'CLAIM_MISSION': {
      const { missionId, rewardPoints } = action.payload;
      if (state.completedMissionIds.includes(missionId)) return state;

      const newState = {
        ...state,
        completedMissionIds: [...state.completedMissionIds, missionId],
        missionsCompleted: state.missionsCompleted + 1,
        totalPoints: state.totalPoints + (rewardPoints || 0),
        notifications: [...state.notifications, {
          type: 'mission',
          title: 'Mission Complete!',
          message: `+${rewardPoints || 0} bonus points!`,
          id: Date.now(),
        }],
      };

      // Re-check badges after mission completion
      const newBadges = evaluateNewBadges(newState, state.badgesEarned);
      if (newBadges.length > 0) {
        newState.badgesEarned = [...newState.badgesEarned, ...newBadges.map((b) => b.id)];
        newBadges.forEach((badge, i) => {
          newState.notifications.push({
            type: 'badge',
            title: 'Badge Unlocked!',
            message: `${badge.icon} ${badge.name}`,
            id: Date.now() + 1 + i,
          });
        });
      }

      return newState;
    }

    case 'DISMISS_NOTIFICATION': {
      return {
        ...state,
        notifications: state.notifications.filter((n) => n.id !== action.payload),
      };
    }

    case 'RECORD_LOGIN': {
      const now = new Date().toISOString();
      const newDates = [...state.activityDates];
      // We don't add the date if there's no activity, just update lastActive
      const streakInfo = computeStreak(newDates);
      return {
        ...state,
        currentStreak: streakInfo.currentStreak,
        longestStreak: Math.max(state.longestStreak, streakInfo.currentStreak),
        lastActiveDate: now,
      };
    }

    case 'LOGIN_USER': {
      return {
        ...state,
        userName: action.payload.name,
      };
    }

    case 'RESET_STATE': {
      localStorage.removeItem(STORAGE_KEY);
      return getInitialState();
    }

    default:
      return state;
  }
}

/* ─── Context ─── */

const GameContext = createContext(null);

export function GameProvider({ children }) {
  const [state, dispatch] = useReducer(gameReducer, null, getInitialState);

  // Persist to localStorage on every state change
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch { /* storage full — ignore */ }
  }, [state]);

  // Record login on mount
  useEffect(() => {
    dispatch({ type: 'RECORD_LOGIN' });
  }, []);

  // Action creators
  const completeActivity = useCallback((activityId, correctAnswers, totalQuestions, topic, hintsUsed = 0) => {
    dispatch({
      type: 'COMPLETE_ACTIVITY',
      payload: { activityId, correctAnswers, totalQuestions, topic, hintsUsed },
    });
  }, []);

  const claimMission = useCallback((missionId, rewardPoints) => {
    dispatch({
      type: 'CLAIM_MISSION',
      payload: { missionId, rewardPoints },
    });
  }, []);

  const dismissNotification = useCallback((notificationId) => {
    dispatch({ type: 'DISMISS_NOTIFICATION', payload: notificationId });
  }, []);

  const loginUser = useCallback((name) => {
    dispatch({ type: 'LOGIN_USER', payload: { name } });
  }, []);

  const resetState = useCallback(() => {
    dispatch({ type: 'RESET_STATE' });
  }, []);

  // Derived values
  const levelInfo = computeLevel(state.totalPoints);
  const streakInfo = computeStreak(state.activityDates);
  const streakMessage = getStreakMessage(streakInfo.currentStreak, streakInfo.isActiveToday);
  const missionProgress = computeMissionProgress(state, state.completedMissionIds);

  // Build full leaderboard users list
  const allUsers = seedUsers.map((u) =>
    u.id === 'user_current'
      ? {
          ...u,
          name: state.userName,
          totalPoints: state.totalPoints,
          badgesEarned: state.badgesEarned,
          currentStreak: state.currentStreak,
          activitiesCompleted: state.activitiesCompleted,
          quizzesCompleted: state.quizzesCompleted,
          missionsCompleted: state.missionsCompleted,
          longestStreak: state.longestStreak,
          level: levelInfo.current.level,
        }
      : u
  );

  const value = {
    ...state,
    levelInfo,
    streakInfo,
    streakMessage,
    missionProgress,
    allUsers,

    // Actions
    completeActivity,
    claimMission,
    dismissNotification,
    loginUser,
    resetState,
  };

  return <GameContext.Provider value={value}>{children}</GameContext.Provider>;
}

export function useGame() {
  const context = useContext(GameContext);
  if (!context) {
    throw new Error('useGame must be used within a GameProvider');
  }
  return context;
}

export default GameContext;

/**
 * Sound Engine — Web Audio API Synthesized Sound Effects
 * 
 * Generates game-like sound effects using the Web Audio API.
 * No external audio files needed — all sounds are synthesized.
 * 
 * Sound categories:
 * - UI feedback (click, hover)
 * - Rewards (points, badge, level up)
 * - Quiz feedback (correct, incorrect)
 * - Achievements (mission complete, streak)
 */

let audioCtx = null;

function getAudioContext() {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  }
  return audioCtx;
}

/**
 * Plays a synthesized tone.
 * @param {number} frequency - Hz
 * @param {string} type - oscillator type (sine, square, triangle, sawtooth)
 * @param {number} duration - seconds
 * @param {number} volume - 0 to 1
 * @param {number} delay - seconds before playing
 */
function playTone(frequency, type = 'sine', duration = 0.15, volume = 0.3, delay = 0) {
  try {
    const ctx = getAudioContext();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(frequency, ctx.currentTime + delay);
    gain.gain.setValueAtTime(volume, ctx.currentTime + delay);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + delay + duration);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(ctx.currentTime + delay);
    osc.stop(ctx.currentTime + delay + duration);
  } catch {
    // Audio not supported — fail silently
  }
}

/**
 * Play a sequence of tones (arpeggio / melody).
 */
function playMelody(notes) {
  notes.forEach(({ freq, type, duration, volume, delay }) => {
    playTone(freq, type || 'sine', duration || 0.15, volume || 0.25, delay || 0);
  });
}

/* ─── Public Sound Effects ─── */

/** Soft click for button/UI interaction */
export function playClick() {
  playTone(800, 'sine', 0.06, 0.15);
}

/** Positive chime for correct answers */
export function playCorrect() {
  playMelody([
    { freq: 523, type: 'sine', duration: 0.1, volume: 0.25, delay: 0 },
    { freq: 659, type: 'sine', duration: 0.1, volume: 0.25, delay: 0.08 },
    { freq: 784, type: 'sine', duration: 0.15, volume: 0.3, delay: 0.16 },
  ]);
}

/** Negative buzz for wrong answers */
export function playIncorrect() {
  playMelody([
    { freq: 250, type: 'square', duration: 0.15, volume: 0.15, delay: 0 },
    { freq: 200, type: 'square', duration: 0.2, volume: 0.12, delay: 0.12 },
  ]);
}

/** Points earned — ascending sparkle */
export function playPoints() {
  playMelody([
    { freq: 880, type: 'sine', duration: 0.08, volume: 0.2, delay: 0 },
    { freq: 1100, type: 'sine', duration: 0.08, volume: 0.2, delay: 0.06 },
    { freq: 1320, type: 'sine', duration: 0.12, volume: 0.25, delay: 0.12 },
  ]);
}

/** Badge unlocked — triumphant fanfare */
export function playBadgeUnlock() {
  playMelody([
    { freq: 523, type: 'triangle', duration: 0.12, volume: 0.3, delay: 0 },
    { freq: 659, type: 'triangle', duration: 0.12, volume: 0.3, delay: 0.1 },
    { freq: 784, type: 'triangle', duration: 0.12, volume: 0.3, delay: 0.2 },
    { freq: 1047, type: 'triangle', duration: 0.3, volume: 0.35, delay: 0.3 },
  ]);
}

/** Level up — epic ascending scale */
export function playLevelUp() {
  playMelody([
    { freq: 440, type: 'sine', duration: 0.1, volume: 0.25, delay: 0 },
    { freq: 554, type: 'sine', duration: 0.1, volume: 0.25, delay: 0.08 },
    { freq: 659, type: 'sine', duration: 0.1, volume: 0.25, delay: 0.16 },
    { freq: 880, type: 'sine', duration: 0.1, volume: 0.3, delay: 0.24 },
    { freq: 1047, type: 'triangle', duration: 0.15, volume: 0.3, delay: 0.32 },
    { freq: 1319, type: 'triangle', duration: 0.3, volume: 0.35, delay: 0.42 },
  ]);
}

/** Mission complete — satisfying resolution */
export function playMissionComplete() {
  playMelody([
    { freq: 392, type: 'triangle', duration: 0.1, volume: 0.25, delay: 0 },
    { freq: 523, type: 'triangle', duration: 0.1, volume: 0.25, delay: 0.1 },
    { freq: 659, type: 'triangle', duration: 0.15, volume: 0.3, delay: 0.2 },
    { freq: 784, type: 'sine', duration: 0.25, volume: 0.3, delay: 0.3 },
  ]);
}

/** Streak notification — quick upward sweep */
export function playStreak() {
  playMelody([
    { freq: 600, type: 'sawtooth', duration: 0.05, volume: 0.12, delay: 0 },
    { freq: 800, type: 'sawtooth', duration: 0.05, volume: 0.12, delay: 0.04 },
    { freq: 1000, type: 'sawtooth', duration: 0.05, volume: 0.15, delay: 0.08 },
    { freq: 1200, type: 'sine', duration: 0.1, volume: 0.2, delay: 0.12 },
  ]);
}

/** Hover effect — very subtle tick */
export function playHover() {
  playTone(1200, 'sine', 0.03, 0.06);
}

/** Navigation transition */
export function playNav() {
  playTone(600, 'sine', 0.08, 0.1);
}

/** Quiz start */
export function playQuizStart() {
  playMelody([
    { freq: 440, type: 'sine', duration: 0.1, volume: 0.2, delay: 0 },
    { freq: 660, type: 'sine', duration: 0.1, volume: 0.25, delay: 0.12 },
    { freq: 880, type: 'triangle', duration: 0.2, volume: 0.3, delay: 0.24 },
  ]);
}

/** Perfect score celebration */
export function playPerfect() {
  playMelody([
    { freq: 523, type: 'sine', duration: 0.08, volume: 0.25, delay: 0 },
    { freq: 659, type: 'sine', duration: 0.08, volume: 0.25, delay: 0.06 },
    { freq: 784, type: 'sine', duration: 0.08, volume: 0.25, delay: 0.12 },
    { freq: 1047, type: 'sine', duration: 0.08, volume: 0.3, delay: 0.18 },
    { freq: 1319, type: 'triangle', duration: 0.08, volume: 0.3, delay: 0.24 },
    { freq: 1568, type: 'triangle', duration: 0.3, volume: 0.35, delay: 0.3 },
  ]);
}

/* ─── Background Music (BGM) ─── */
let bgmBuffer = null;
let bgmSource = null;
let isBgmPlaying = false;
let isBgmLoading = false;

export async function playBGM(url = import.meta.env.BASE_URL + 'bgm.m4a') {
  if (isBgmPlaying) return;
  const ctx = getAudioContext();

  if (ctx.state === 'suspended') {
    await ctx.resume();
  }

  // Prevent multiple simultaneous fetches
  if (isBgmLoading) return;
  isBgmLoading = true;

  try {
    if (!bgmBuffer) {
      const response = await fetch(url);
      const arrayBuffer = await response.arrayBuffer();
      bgmBuffer = await ctx.decodeAudioData(arrayBuffer);
    }

    if (isBgmPlaying) {
      isBgmLoading = false;
      return; 
    }

    // Double check we don't duplicate on race condition
    if (bgmSource) {
      try {
        bgmSource.stop();
      } catch (e) {}
      bgmSource.disconnect();
    }

    bgmSource = ctx.createBufferSource();
    bgmSource.buffer = bgmBuffer;
    bgmSource.loop = true;

    const gainNode = ctx.createGain();
    gainNode.gain.value = 0.15; // Set volume to match Youtube player (15%)

    bgmSource.connect(gainNode);
    gainNode.connect(ctx.destination);

    bgmSource.start(0);
    isBgmPlaying = true;
  } catch (err) {
    console.warn("Failed to build/play BGM:", err);
  } finally {
    isBgmLoading = false;
  }
}

export function stopBGM() {
  if (bgmSource) {
    try {
      bgmSource.stop();
    } catch (e) {}
    bgmSource.disconnect();
    bgmSource = null;
  }
  isBgmPlaying = false;
}

/**
 * Profile / Progress Page
 * 
 * Shows the user's engagement history, personal statistics,
 * growth over time, and a summary of all gamification metrics.
 */

import { useGame } from '../context/GameContext';
import { computeLevel } from '../engine/levelEngine';
import { computeAnalytics } from '../engine/analyticsEngine';
import { getAllBadgesWithStatus } from '../engine/badgeEngine';
import ProgressBar from '../components/ProgressBar';

export default function ProfilePage() {
  const game = useGame();
  const analytics = computeAnalytics(game, game.activityLog);
  const badges = getAllBadgesWithStatus(game.badgesEarned);
  const earnedBadges = badges.filter((b) => b.unlocked);

  return (
    <div>
      {/* Profile Header */}
      <div className="profile-header">
        <span className="profile-avatar">{game.userAvatar}</span>
        <div>
          <h1 className="profile-name">{game.userName}</h1>
          <p className="profile-joined">Joined {game.joinDate}</p>
          <div className="profile-level-badge">
            {game.levelInfo.current.icon} Level {game.levelInfo.current.level} — {game.levelInfo.current.title}
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="stats-grid" style={{ gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))' }}>
        <div className="stat-card">
          <div className="stat-card-icon">⭐</div>
          <div className="stat-card-value">{game.totalPoints.toLocaleString()}</div>
          <div className="stat-card-label">Total Points</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon">📚</div>
          <div className="stat-card-value">{analytics.totalActivities}</div>
          <div className="stat-card-label">Activities</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon">🎯</div>
          <div className="stat-card-value">{analytics.avgAccuracy}%</div>
          <div className="stat-card-label">Avg Accuracy</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon">🔥</div>
          <div className="stat-card-value">{game.currentStreak}</div>
          <div className="stat-card-label">Current Streak</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon">⚡</div>
          <div className="stat-card-value">{game.longestStreak}</div>
          <div className="stat-card-label">Longest Streak</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon">🏆</div>
          <div className="stat-card-value">{earnedBadges.length}/{badges.length}</div>
          <div className="stat-card-label">Badges</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon">🎯</div>
          <div className="stat-card-value">{analytics.missionsCompleted}/{analytics.totalMissionsAvailable}</div>
          <div className="stat-card-label">Missions</div>
        </div>
        <div className="stat-card">
          <div className="stat-card-icon">📊</div>
          <div className="stat-card-value">{analytics.engagementScore}</div>
          <div className="stat-card-label">Engagement</div>
        </div>
      </div>

      <div className="two-col">
        <div>
          {/* Activity History (Last 7 Days) */}
          <div className="card mb-xl">
            <h3 style={{ fontWeight: 700, marginBottom: '16px' }}>📈 Activity This Week</h3>
            <div className="bar-chart">
              {analytics.last7Days.map((day) => {
                const maxCount = Math.max(1, ...analytics.last7Days.map((d) => d.count));
                const heightPercent = (day.count / maxCount) * 100;
                return (
                  <div key={day.date} className="bar-chart-bar">
                    <div className="bar-chart-value">{day.count}</div>
                    <div className="bar-chart-fill" style={{ height: `${Math.max(4, heightPercent)}%` }} />
                    <div className="bar-chart-label">{day.day}</div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Topic Distribution */}
          <div className="card mb-xl">
            <h3 style={{ fontWeight: 700, marginBottom: '16px' }}>🗂️ Topic Progress</h3>
            {['programming', 'logic', 'digital'].map((topic) => {
              const count = analytics.topicDistribution[topic] || 0;
              const topicNames = { programming: '💻 Programming', logic: '🧩 Logic', digital: '🌐 Digital Skills' };
              return (
                <div key={topic} style={{ marginBottom: '12px' }}>
                  <ProgressBar
                    value={count}
                    max={5}
                    label={topicNames[topic]}
                    sublabel={`${count} activities`}
                  />
                </div>
              );
            })}
          </div>
        </div>

        <div>
          {/* Level Progress */}
          <div className="card mb-xl">
            <h3 style={{ fontWeight: 700, marginBottom: '12px' }}>📈 Level Progress</h3>
            <div style={{ textAlign: 'center', marginBottom: '12px' }}>
              <span style={{ fontSize: '2.5rem' }}>{game.levelInfo.current.icon}</span>
              <div style={{ fontWeight: 700, marginTop: '4px' }}>
                Level {game.levelInfo.current.level}
              </div>
              <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                {game.levelInfo.current.title}
              </div>
            </div>
            {!game.levelInfo.isMaxLevel && (
              <ProgressBar
                value={game.levelInfo.xpIntoLevel}
                max={game.levelInfo.xpForNextLevel}
                label="Next Level"
                sublabel={`${game.levelInfo.xpIntoLevel}/${game.levelInfo.xpForNextLevel} XP`}
                large
              />
            )}
            <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginTop: '8px' }}>
              Perk: {game.levelInfo.current.perks}
            </p>
          </div>

          {/* Earned Badges Showcase */}
          <div className="card mb-xl">
            <h3 style={{ fontWeight: 700, marginBottom: '12px' }}>🏆 Badge Collection</h3>
            {earnedBadges.length === 0 ? (
              <p className="text-muted" style={{ fontSize: '0.85rem' }}>No badges earned yet.</p>
            ) : (
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                {earnedBadges.map((badge) => (
                  <div key={badge.id} style={{
                    padding: '8px 12px',
                    background: 'var(--bg-glass)',
                    borderRadius: 'var(--radius-md)',
                    textAlign: 'center',
                    fontSize: '0.8rem',
                  }} title={badge.description}>
                    <span style={{ fontSize: '1.4rem' }}>{badge.icon}</span>
                    <div style={{ fontWeight: 600, marginTop: '2px' }}>{badge.name}</div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Reset button for demo purposes */}
          <div className="card" style={{ textAlign: 'center' }}>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '8px' }}>Demo Controls</p>
            <button className="btn btn-secondary btn-sm" onClick={game.resetState}>
              🔄 Reset All Progress
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

